// // This is a synchronous reset for the Johnson counter, which will set the counter to 3'b111 when reset.
module johnson_counter(
    input clk,
    input reset,
    output reg [2:0] q);always @(posedge clk)
    if (reset)
        q <= 3'b000;
    else
        q <= {~q[0], q[2:1]};

endmodule
